static const uint8_t _amplitude_coeffs_default[35] = { 90,  103, 111, 114, 99,  107, 131, 145, 144, 119, 123, 156,
                                                 178, 179, 139, 127, 164, 191, 181, 141, 119, 151, 173, 170,
                                                 133, 103, 122, 135, 135, 114, 88,  101, 107, 112, 96 };


void vl53l9_calib_default_apply(vl53l9_calib_data_t *calib) {

    if (calib == NULL) {
        return;
    }

    calib->global_offset = -2;
    (void)memcpy(calib->distance_offset, _distance_offset_default, sizeof(calib->distance_offset));
    calib->optical_offset_x = 0;
    calib->optical_offset_y = 0;
    calib->residual_offset_x = -0.5f;
    calib->residual_offset_y = -0.5f;
    calib->rad2perp_fov_gain = 1.0f;
    (void)memcpy(calib->amplitude_coeffs, _amplitude_coeffs_default, sizeof(calib->amplitude_coeffs));
    calib->amplitude_scaler = 18;
    calib->amplitude_distance = 400;
    calib->amplitude_exposure = 33884;
    calib->amplitude_reflectance = 3;

    const float _dss_short_effective_spad[8] = { 0.015f, 0.16f, 0.106f, 0.22f, 3.0f, 6.0f, 10.0f, 0.0f };
    const float _dss_long_effective_spad[8] = { 0.015f, 0.16f, 0.106f, 0.22f, 3.0f, 6.0f, 10.0f, 0.0f };
    (void)memcpy(calib->dss_short_effective_spad, _dss_short_effective_spad, sizeof(calib->dss_short_effective_spad));
    (void)memcpy(calib->dss_long_effective_spad, _dss_long_effective_spad, sizeof(calib->dss_long_effective_spad));
}

